const entry = $json.item;
const contactName = entry.contactName || 'cliente';
const customerFormUrl = $env.KINGESTION_CUSTOMER_FORM_URL ?? '';
const pickupAddress = $env.KINGESTION_PICKUP_ADDRESS ?? 'Sucursal ANYX';
const internalKingstonRequestEmail = $env.KINGESTION_KINGSTON_REQUEST_EMAIL ?? 'gdelcastillo@anyx.com.ar';
const purchasingEmail = $env.KINGESTION_PURCHASING_EMAIL ?? 'compras@anyx.com.ar';
const technicalEmail = $env.KINGESTION_TECH_EMAIL ?? 'serviciotecnico@anyx.com.ar';

const base = {
  caseId: entry.id,
  clientName: entry.clientName,
  contactName,
  contactEmail: entry.contactEmail,
  status: entry.externalStatus,
  zone: entry.zone,
  nextAction: entry.nextAction,
  internalNumber: entry.internalNumber,
  kingstonNumber: entry.kingstonNumber,
  transporter: entry.logistics.transporter,
  guideNumber: entry.logistics.guideNumber,
  trackingUrl: entry.logistics.trackingUrl,
  customerFormUrl,
  pickupAddress,
  includeAiDraft: true
};

const emails = [];
const pushEmail = (payload) => emails.push({ json: { ...base, ...payload } });

switch (entry.externalStatus) {
  case 'Aviso de envio':
    if (!entry.contactEmail) return [];
    pushEmail({
      templateSlug: 'cliente-instrucciones-envio-y-formulario',
      recipientType: 'cliente',
      destinationEmail: entry.contactEmail,
      subjectHint: 'Instrucciones de envío del producto fallado',
      purpose: 'Solicitar al end user el envío del producto fallado a ANYX, pedir el comprobante oficial del correo con el costo del envío y recordarle que complete el formulario web con datos de entrega y datos bancarios para reintegro.',
      contextNotes: customerFormUrl
        ? `Incluí el enlace al formulario web ${customerFormUrl} y explicá que allí debe completar datos de entrega del reemplazo y datos bancarios para el reintegro del envío fallado.`
        : 'Indicá que debe completar el formulario web definido por ANYX con datos de entrega y bancarios para el reintegro.'
    });
    break;
  case 'Producto recepcionado y en preparacion':
    if (!entry.contactEmail) return [];
    pushEmail({
      templateSlug: 'cliente-recepcion-confirmada',
      recipientType: 'cliente',
      destinationEmail: entry.contactEmail,
      subjectHint: 'Recepción confirmada del producto fallado',
      purpose: 'Confirmar al end user que ANYX recibió el producto fallado y que el caso sigue en preparación y validación interna.',
      contextNotes: 'El correo debe ser breve y confirmar únicamente la recepción del producto fallado.'
    });
    break;
  case 'OV creada':
    pushEmail({
      templateSlug: 'interno-compras-ov-creada',
      recipientType: 'interno',
      destinationEmail: purchasingEmail,
      subjectHint: 'Acción pendiente de compras sobre OV creada',
      purpose: 'Avisar a compras que la OV ya fue creada en Kingestion y que debe definir disponibilidad local, compra o continuidad del circuito.',
      contextNotes: 'Este aviso adapta el antiguo pedido de liberación de mercadería del circuito SharePoint al estado actual OV creada.'
    });
    break;
  case 'Pedido Kingston':
    pushEmail({
      templateSlug: 'interno-gustavo-pedido-kingston',
      recipientType: 'interno',
      destinationEmail: internalKingstonRequestEmail,
      subjectHint: 'Solicitud para consolidar pedido a Kingston',
      purpose: 'Enviar a Gustavo del Castillo la información del caso, la parte faltante y el SKU de reemplazo para consolidar el pedido a Kingston con otros faltantes.',
      contextNotes: 'El correo debe quedar orientado a consolidación de pedido a Kingston EEUU y mencionar que se trata de reposición por falta local.'
    });

    if (entry.contactEmail) {
      pushEmail({
        templateSlug: 'cliente-demora-por-falta-local',
        recipientType: 'cliente',
        destinationEmail: entry.contactEmail,
        subjectHint: 'Reposición solicitada a Kingston EEUU',
        purpose: 'Informar al cliente que no hay stock local ni mayorista y que el reemplazo fue solicitado a Kingston EEUU.',
        contextNotes: 'Debe explicar la demora de forma clara, sin prometer una fecha exacta si no existe.'
      });
    }
    break;
  case 'Pedido deposito y etiquetado':
    pushEmail({
      templateSlug: 'interno-servicio-tecnico-catalogacion',
      recipientType: 'interno',
      destinationEmail: technicalEmail,
      subjectHint: 'Catalogación y disposición de reemplazo RMA',
      purpose: 'Solicitar a servicio técnico que catalogue el producto como RMA y lo disponga para envío o retiro según la zona y modalidad del caso.',
      contextNotes: entry.zone === 'Interior / Gran Buenos Aires'
        ? 'Aclará que el producto debe quedar dispuesto para despacho al cliente y que la guía puede cargarse más tarde dentro de Kingestion.'
        : 'Aclará que el producto debe quedar dispuesto para retiro del cliente en ANYX.'
    });
    break;
  case 'Producto enviado':
    if (!entry.contactEmail) return [];
    pushEmail({
      templateSlug: 'cliente-despacho-confirmado',
      recipientType: 'cliente',
      destinationEmail: entry.contactEmail,
      subjectHint: 'Despacho confirmado del reemplazo',
      purpose: 'Informar al cliente que ANYX ya despachó el producto de reemplazo hacia el domicilio definido.',
      contextNotes: entry.logistics.guideNumber
        ? 'Incluí guía, transportista y tracking si están disponibles.'
        : 'Indicá que el despacho ya fue realizado y que la guía o tracking se informarán apenas estén disponibles.'
    });
    break;
  case 'Producto listo para retiro':
    if (!entry.contactEmail) return [];
    pushEmail({
      templateSlug: 'cliente-retiro-disponible',
      recipientType: 'cliente',
      destinationEmail: entry.contactEmail,
      subjectHint: 'Producto listo para retiro',
      purpose: 'Informar al cliente que el reemplazo ya está disponible para retiro en ANYX y explicarle cómo coordinarlo.',
      contextNotes: `Incluí la dirección o punto de retiro configurado por ANYX: ${pickupAddress}.`
    });
    break;
  case 'Realizado':
  case 'Vencido':
  case 'Cerrado':
    if (!entry.contactEmail) return [];
    pushEmail({
      templateSlug: 'cliente-cierre-caso',
      recipientType: 'cliente',
      destinationEmail: entry.contactEmail,
      subjectHint: 'Cierre del caso',
      purpose: 'Informar al cliente el cierre final del caso con el contexto correspondiente al estado terminal actual.',
      contextNotes: 'Si el estado es Realizado, reflejar resolución exitosa. Si es Vencido o Cerrado, dejar el motivo en términos administrativos y claros.'
    });
    break;
  default:
    return [];
}

return emails;

